/**
 * T46-6 (Issue #99) — Golden Core contract.
 *
 * Defines the single, versioned, auditable registry types for the
 * ProjectFlow Golden Core suite.
 *
 * Boundary invariants (enforced in {@link golden-core-registry.ts}):
 *  - TypeScript is the SINGLE source of truth. The JSON snapshot under
 *    `agent-bridge/golden-core/registry.json` is a frozen audit artifact
 *    generated by an explicit `freeze` command. Normal runs verify the TS
 *    fingerprint matches the checked-in JSON fingerprint; mismatch is
 *    fail-closed.
 *  - Each canonical scenario ID is unique.
 *  - Semantic duplication (same goal/fingerprint/capability+class overlap)
 *    is detected and rejected at registry build time.
 *  - Unsupported future schema versions fail-closed.
 *  - Suite freeze produces a reviewable Git diff on the JSON snapshot;
 *    normal runs cannot mutate the frozen registry.
 *  - Robustness variants attach to a canonical scenario and do NOT count
 *    toward the canonical scenario total.
 *  - Generated regression candidates live in a separate candidate registry
 *    and cannot be auto-promoted.
 *
 * Issue #99 §3 (trusted entry conditions): every stateful scenario in the
 * frozen suite MUST declare:
 *  1. independent goal provenance
 *  2. deterministic fixture/seed + fingerprint
 *  3. independent Golden Constraints / hidden goals
 *  4. executable + solvable Reference Program
 *  5. Reference Program does NOT generate the oracle
 *  6. declared grader mutations
 *  7. mutation detection evidence
 *  8. explicit viewer/workspace/project/conversation/run scope
 *  9. explicit required/allowed/forbidden/unchanged state + (when applicable)
 *     Golden Milestone DAG
 *
 * Missing any entry condition → the scenario is `candidate` or `rejected`,
 * NOT silently counted as canonical.
 */

import type { ScenarioContract } from "./contract.js";
import type { ReferenceProgram } from "./contract-v2.js";

// ---------------------------------------------------------------------------
// §1 Versions
// ---------------------------------------------------------------------------

/** Golden Core registry schema version. Bump when registry shape changes. */
export const GOLDEN_CORE_SCHEMA_VERSION = 1 as const;

/**
 * Golden Core suite version. Bump when the canonical scenario set changes
 * (add, remove, or materially modify a scenario). The JSON snapshot's
 * `suiteVersion` must match this value at verification time.
 */
export const GOLDEN_CORE_SUITE_VERSION = 1 as const;

/**
 * Stable default `frozenAt` timestamp for the in-memory Golden Core
 * registry. This MUST be a constant — never `new Date().toISOString()` —
 * so that `buildGoldenCoreRegistry()` produces a deterministic
 * fingerprint across builds. The `freezeRegistry()` helper overrides
 * this with the real wall-clock time when it writes the JSON snapshot,
 * but the in-memory registry built by `buildGoldenCoreRegistry()`
 * (which is what the fingerprint is computed over) stays reproducible.
 *
 * The value matches the date Issue #99 was started (2026-07-20 UTC).
 */
export const GOLDEN_CORE_DEFAULT_FROZEN_AT = "2026-07-20T00:00:00.000Z";

