// ---------------------------------------------------------------------------
// §4 P0 categories (protected, immutable set)
// ---------------------------------------------------------------------------

/**
 * P0 protected categories. At least one scenario per category MUST remain
 * in every preset that claims P0 coverage. {@link P0_MANDATORY_CATEGORIES}
 * is the frozen immutable set.
 */
export type P0Category =
  | "safety-authority"
  | "privacy-visibility"
  | "proposal-confirm"
  | "idempotency"
  | "forbidden-side-effects"
  | "terminal-consistency"
  | "read-only-purity"
  | "hidden-field-leakage";

export const P0_MANDATORY_CATEGORIES: readonly P0Category[] = [
  "safety-authority",
  "privacy-visibility",
  "proposal-confirm",
  "idempotency",
  "forbidden-side-effects",
  "terminal-consistency",
  "read-only-purity",
  "hidden-field-leakage",
] as const;

// ---------------------------------------------------------------------------
// §5 Priority levels
// ---------------------------------------------------------------------------

export type ScenarioPriority = "P0" | "P1" | "P2";

// ---------------------------------------------------------------------------
// §6 Robustness variant kinds (6, attached to canonical scenario)
// ---------------------------------------------------------------------------

export type RobustnessVariantKind =
  | "semantic-paraphrase"
  | "distraction-injection"
  | "description-weakening"
  | "irrelevant-context"
  | "order-variation"
  | "bounded-adversarial-wording";

export const ROBUSTNESS_VARIANT_KINDS: readonly RobustnessVariantKind[] = [
  "semantic-paraphrase",
  "distraction-injection",
  "description-weakening",
  "irrelevant-context",
  "order-variation",
  "bounded-adversarial-wording",
] as const;

// ---------------------------------------------------------------------------
// §7 Golden Core scenario entry
// ---------------------------------------------------------------------------

/**
 * Metadata declaring the trusted entry conditions for a canonical scenario.
 * Every field is required for `status: "canonical"`. Missing any field
 * forces `status: "candidate"` or `status: "rejected"`.
 */
export interface GoldenCoreEntryConditions {
  /**
   * Independent goal provenance: a stable string identifying where the
   * scenario goal comes from (e.g., "spec:user-story-3", "adversarial:A-04").
   * Two scenarios sharing the same provenance root AND the same capability+
   * class+priority are flagged as potential duplicates.
   */
  goalProvenance: string;
  /**
   * Deterministic fixture/seed description. Must be specific enough that
   * two independent authors would produce an equivalent fixture. The
   * `fixtureFingerprint` is a SHA-256 over the canonical fixture payload
   * (computed by the registry, not authored by hand).
   */
  fixtureSeed: string;
  fixtureFingerprint: string;
  /**
   * Independent Golden Constraints / hidden goals. Authored separately
   * from the Reference Program. The oracle is the HardGraderContract on
   * the ScenarioContract — this field documents that the oracle was
   * authored without reference to the Reference Program.
   */
  goldenConstraintsSummary: string;
  /**
   * Reference Program that proves the fixture is reachable and the target
   * state is observable. MUST NOT generate the oracle.
   */
  referenceProgramId: string;
  /**
   * Declared grader mutations targeting this scenario's oracle. Each ID
   * corresponds to a MutationCase in the mutation registry.
   */
  declaredGraderMutations: string[];
  /**
   * Mutation detection evidence: how many of the declared mutations were
   * verified to be detected by their targeted grader. This is populated
   * by the registry builder after running the mutation suite.
   */
  mutationDetectionEvidence: {
    declared: number;
    detected: number;
    missedMutationIds: string[];
  };
  /**
   * Explicit scope. `viewerUserId` is the primary user the Agent acts on
   * behalf of. `adversaryUserId` is set when the scenario has a privacy
   * adversary. `conversationId`/`runId` are optional scoping constraints.
   */
  scope: {
    workspaceId: string;
    projectId: string;
    viewerUserId: string;
    adversaryUserId?: string;
    conversationId?: string;
    runId?: string;
  };
  /**
   * Required/allowed/forbidden/unchanged state summary. This mirrors the
   * HardGraderContract.stateConstraints but is a human-readable summary
   * used for coverage reports and duplicate detection. The authoritative
   * state constraints live on the ScenarioContract.hardGrader.
   */
  stateEffectSummary: {
    required: string[];
    allowed: string[];
    forbidden: string[];
    unchanged: string[];
  };
  /**
   * Golden Milestone DAG summary, when applicable. `null` when the
   * scenario has no ordering constraint. The authoritative DAG lives on
   * ScenarioContract.hardGrader.milestoneDag.
   */
  milestoneDagSummary: string | null;
}

/**
 * A robustness variant attached to a canonical scenario. Variants do NOT
 * count toward the canonical scenario total. Each variant inherits the
 * parent's hidden-goal fingerprint, Golden Constraints, and Reference
 * Program. If a variant changes the task's true meaning, it is rejected
 * with `goalChanged: true`.
 */
export interface RobustnessVariant {
  /** Stable variant ID, unique within the parent scenario. */
  variantId: string;
  /** Parent canonical scenario ID. */
  parentScenarioId: string;
  /** Variant kind. */
  kind: RobustnessVariantKind;
  /** Human-readable description of what the variant changes. */
  description: string;
  /** Modified prompt to send to the Agent. Must preserve the hidden goal. */
  promptOverride: string;
  /**
   * SHA-256 of the parent scenario's hidden-goal fingerprint. The variant
   * MUST inherit this; if the variant's own hidden-goal fingerprint
   * differs, `goalChanged` is set to true and the variant is rejected.
   */
  inheritedHiddenGoalFingerprint: string;
  /** Set to true when the variant changes the task's true meaning. */
  goalChanged: boolean;
  /** Whether the variant passed robustness verification. */
  verified: boolean;
}

/**
 * Entry status. Only `canonical` entries count toward the canonical total.
 * `candidate` entries are pending entry-condition verification.
 * `rejected` entries failed verification and are retained for audit.
 */
export type GoldenCoreEntryStatus = "canonical" | "candidate" | "rejected";

/**
 * A Golden Core scenario entry. Wraps the existing ScenarioContract with
 * Golden Core metadata.
 */
export interface GoldenCoreScenarioEntry {
  /** Stable scenario ID; matches ScenarioContract.scenarioId. */
  scenarioId: string;
  /** Schema version of the entry (not the scenario contract). */
  schemaVersion: typeof GOLDEN_CORE_SCHEMA_VERSION;
  /** Scenario version; bump when the scenario materially changes. */
  scenarioVersion: number;
  /** The underlying ScenarioContract (prompt, hidden, hardGrader, etc.). */
  scenario: ScenarioContract;
  /** Capability domain. */
  capability: CapabilityDomain;
  /** Scenario class. */
  scenarioClass: ScenarioClass;
  /** Priority level. */
  priority: ScenarioPriority;
  /** P0 categories this scenario protects. Empty for P1/P2. */
  p0Categories: P0Category[];
  /** Reference Program for this scenario. */
  referenceProgram: ReferenceProgram;
  /** Trusted entry conditions. Required for `canonical` status. */
  entryConditions: GoldenCoreEntryConditions;
  /** Robustness variants attached to this scenario. */
  robustnessVariants: RobustnessVariant[];
  /** Entry status. */
  status: GoldenCoreEntryStatus;
  /** Rejection reason, when status is `rejected`. */
  rejectionReason?: string;
  /** Human-readable summary for coverage reports. */
  summary: string;
}

// ---------------------------------------------------------------------------
// §8 Golden Core registry
// ---------------------------------------------------------------------------

/**
 * The Golden Core registry. This is the single source of truth.
 * The JSON snapshot under `agent-bridge/golden-core/registry.json` is a
 * frozen audit artifact generated from this structure.
 */
export interface GoldenCoreRegistry {
  schemaVersion: typeof GOLDEN_CORE_SCHEMA_VERSION;
  suiteVersion: typeof GOLDEN_CORE_SUITE_VERSION;
  registryId: string;
  /** Canonical entries (status === "canonical"). */
  canonical: GoldenCoreScenarioEntry[];
  /** Candidate entries (status === "candidate"). */
  candidates: GoldenCoreScenarioEntry[];
  /** Rejected entries (status === "rejected"), retained for audit. */
  rejected: GoldenCoreScenarioEntry[];
  /** SHA-256 fingerprint over the canonical set. */
  fingerprint: string;
  /** ISO timestamp of when the registry was last frozen. */
  frozenAt: string;
  /** Optional notes for the freeze record. */
  freezeNotes?: string;
}

// ---------------------------------------------------------------------------
// §9 Coverage matrix report
// ---------------------------------------------------------------------------

export interface CoverageCell {
  capability: CapabilityDomain;
  scenarioClass: ScenarioClass;
  scenarioIds: string[];
  count: number;
}

export interface PriorityDistribution {
  P0: number;
  P1: number;
  P2: number;
}

export interface ClassDistribution {
  scenarioClass: ScenarioClass;
  count: number;
  scenarioIds: string[];
}

export interface CapabilityDistribution {
  capability: CapabilityDomain;
  count: number;
  scenarioIds: string[];
}

export interface P0CategoryCoverage {
  category: P0Category;
  scenarioIds: string[];
  covered: boolean;
}

export interface HardGateCoverage {
  graderName: string;
  scenarioIds: string[];
  count: number;
}

export interface MutationCoverage {
  scenarioId: string;
  declared: number;
  detected: number;
  missedMutationIds: string[];
  fullyDetected: boolean;
}

export interface ReferenceSolvabilityEntry {
  scenarioId: string;
  referenceProgramId: string;
  solvable: boolean;
  hardFalseFailures: number;
}

export interface CoverageGap {
  kind: "missing-capability-class" | "missing-p0-category" | "missing-hard-gate" | "low-mutation-detection" | "unsolvable-reference";
  description: string;
  affected: string[];
}

export interface DuplicateRisk {
  kind: "shared-goal-provenance" | "shared-fixture-fingerprint" | "capability-class-priority-overlap";
  description: string;
  scenarioIds: string[];
}

export interface CoverageMatrixReport {
  schemaVersion: typeof GOLDEN_CORE_SCHEMA_VERSION;
  suiteVersion: typeof GOLDEN_CORE_SUITE_VERSION;
  registryFingerprint: string;
  generatedAt: string;
  canonicalCount: number;
  candidateCount: number;
  rejectedCount: number;
  robustnessVariantCount: number;
  capabilityClassMatrix: CoverageCell[];
  capabilityDistribution: CapabilityDistribution[];
  classDistribution: ClassDistribution[];
  priorityDistribution: PriorityDistribution;
  p0CategoryCoverage: P0CategoryCoverage[];
  hardGateCoverage: HardGateCoverage[];
  mutationCoverage: MutationCoverage[];
  referenceSolvability: ReferenceSolvabilityEntry[];
  gaps: CoverageGap[];
  duplicateRisks: DuplicateRisk[];
  exclusions: Array<{ scenarioId: string; reason: string }>;
  skips: Array<{ scenarioId: string; reason: string }>;
  errors: Array<{ scenarioId: string; code: string; message: string }>;
}

// ---------------------------------------------------------------------------
// §10 Regression candidate governance
// ---------------------------------------------------------------------------

/**
 * A generated regression candidate. Lives in the candidate registry and
 * cannot be auto-promoted. Promotion requires explicit
 * {@link RegressionPromotionApproval} with all 8 verification checks.
 */
export interface RegressionCandidate {
  candidateId: string;
  schemaVersion: typeof GOLDEN_CORE_SCHEMA_VERSION;
  scenario: ScenarioContract;
  referenceProgram: ReferenceProgram;
  capability: CapabilityDomain;
  scenarioClass: ScenarioClass;
  priority: ScenarioPriority;
  /** Where this candidate was extracted from (e.g., "diagnosis:run-xyz"). */
  sourceProvenance: string;
  /** ISO timestamp of extraction. */
  extractedAt: string;
  /**
   * Verification checks. ALL must pass before promotion. A check that has
   * not been run yet has `status: "pending"`.
   */
  verificationChecks: RegressionCandidateVerificationChecks;
  /** Promotion approval, when granted. */
  promotionApproval?: RegressionPromotionApproval;
  /** Candidate status. */
  status: "pending" | "promoted" | "rejected";
  rejectionReason?: string;
}

export interface RegressionCandidateVerificationChecks {
  representativeness: VerificationCheckResult;
  redaction: VerificationCheckResult;
  hiddenGoalIntegrity: VerificationCheckResult;
  nonDuplicationWithCanonical: VerificationCheckResult;
  fixtureSolvability: VerificationCheckResult;
  graderMutationDeclaration: VerificationCheckResult;
  reviewableDiff: VerificationCheckResult;
  explicitApprovalRecord: VerificationCheckResult;
}

export interface VerificationCheckResult {
  status: "pending" | "passed" | "failed";
  evidence?: string;
  checkedAt?: string;
  failureReason?: string;
}

/**
 * Promotion approval record. Mirrors the Slice 3 pattern: based on
 * repository governance, NOT cryptography. Requires explicit Robert
 * instruction + reviewable Git diff + matching fingerprints + all
 * conflicts resolved.
 */
export interface RegressionPromotionApproval {
  approvalId: string;
  candidateId: string;
  approvedBy: string;
  approvedAt: string;
  /** Git commit hash of the promotion diff. */
  commitHash: string;
  /** Matching fingerprint of the candidate at approval time. */
  candidateFingerprint: string;
  /** Notes from the approver. */
  notes?: string;
}

// ---------------------------------------------------------------------------
// §11 Preset budget invariants (re-declared for Golden Core enforcement)
// ---------------------------------------------------------------------------

/**
 * Golden Core budget invariants. These mirror the Slice 1/3 values and
 * are re-declared here so the Golden Core validator can fail-closed if
 * a preset attempts to raise them.
 */
export const GOLDEN_CORE_BUDGET_INVARIANTS = {
  full: {
    maxSutCostUsd: 1.00,
    maxObservations: 30,
  },
  calibrate: {
    maxSutCostUsd: 3.00,
    maxObservations: 30,
  },
} as const;

// ---------------------------------------------------------------------------
// §12 Scope filter protection
// ---------------------------------------------------------------------------

/**
 * Result of verifying that a scope filter (e.g., `--scenario`, `--exclude`)
 * does not silently remove P0 mandatory scenarios.
 */
export interface P0ScopeFilterVerification {
  passed: boolean;
  missingP0ScenarioIds: string[];
  missingP0Categories: P0Category[];
  /** Mandatory additions the caller MUST include to satisfy P0. */
  mandatoryAdditions: string[];
  failureReason?: string;
}
